/*AdminComm_SQL.selectMenuNmDupliChk*/
SELECT COUNT(*)
  FROM TB_ADMIN_MENU_INFO
WHERE 1=1
    AND MENU_NM = #{uniqueKey}
    AND MENU_DEL_YN = 'N'

/*AdminComm_SQL.selectCommGroupCdDupliChk*/
SELECT COUNT(*)
  FROM TB_COMMON_INFO
WHERE 1=1
    AND COMM_GROUP_CD = #{uniqueKey}
    AND COMM_DEL_YN = 'N'

/*AdminComm_SQL.selectUnitCdDupliChk*/
SELECT COUNT(*)
  FROM TB_ADMIN_UNIT_INFO
WHERE 1=1
    AND ADMIN_UNIT_CD = #{uniqueKey}
    AND ADMIN_UNIT_DEL_YN = 'N'

/*AdminComm_SQL.selectAdminIdDupliChk*/
SELECT COUNT(*)
  FROM TB_ADMIN_INFO
WHERE 1=1
    AND ADMIN_ID = #{uniqueKey}
    AND ADMIN_DEL_YN = 'N'

mapper.insert:
/*AdminComm_SQL.adminCommReg*/
INSERT INTO TB_ADMIN_MENU_FAVORITE (
	  MENU_FAVORITE_ID
	, MENU_FAVORITE_MENU_ID
	, MENU_FAVORITE_ADMIN_ID
	, MENU_FAVORITE_URL
    , MENU_FAVORITE_P_NM
	, MENU_FAVORITE_NM
	, REG_ID
	, REG_DT
	, UPD_ID
	, UPD_DT
) VALUES (
	  (SELECT FN_GET_UNIQUE_KEY())
	, #{menuFavoriteMenuId}
	, #{menuFavoriteAdminId}
	, #{menuFavoriteUrl}
	, #{menuFavoritePNm}
	, #{menuFavoriteNm}
	, #{regId}
	, NOW()
	, #{updId}
	, NOW()
);

mapper.delete:
/*AdminComm_SQL.deleteFavoriteMenu*/
DELETE 
   FROM TB_ADMIN_MENU_FAVORITE
 WHERE 1=1 
     AND MENU_FAVORITE_MENU_ID = #{menuFavoriteMenuId}
     AND MENU_FAVORITE_URL = #{menuFavoriteUrl}

